	alter table dbo.TI17REQJOBPLAN drop constraint FK_REQST_REQJOBPLAN_IFRS17
go

if exists (select 1 
            from  sysobjects c 
            join  sysconstraints s on (s.constrid = c.id and s.tableid = object_id('dbo.TI17REQCHN'))
            where name = 'FK_CHAIN_REQST_CHAIN' and type = 'RI')
            
            ALTER TABLE dbo.TI17REQCHN           DROP CONSTRAINT FK_CHAIN_REQST_CHAIN
go 

