            from  sysobjects c 
            join  sysconstraints s on (s.constrid = c.id and s.tableid = object_id('dbo.TI17REQCHN'))
            where name = 'FK_FNCT_REQST_CHAIN' and type = 'RI')
            
            ALTER TABLE dbo.TI17REQCHN           DROP CONSTRAINT FK_FNCT_REQST_CHAIN
go 

if exists (select 1 
            from  sysobjects c 
            join  sysconstraints s on (s.constrid = c.id and s.tableid = object_id('dbo.TI17REQCHN'))
            where name = 'FK_REQST_REQST_CHAI' and type = 'RI')
            
            ALTER TABLE dbo.TI17REQCHN           DROP CONSTRAINT FK_REQST_REQST_CHAI
go 

